k=os.environ.get('KARAKEEP_API_KEY','')
s=requests.Session();s.headers['Authorization']=f'Bearer {k}'
ROOT='ipnsyy1t55vakjtzkn25y1p0';COLL='sme_salesengineer'
# --- replicate ingest.py routing ---
def fetch_lists():
  o={};c=None
  while True:
    p={'limit':100}
    if c:p['cursor']=c
    d=s.get(f'{b}/api/v1/lists',params=p,timeout=30).json()
    for L in d.get('lists',[]):o[L['id']]={'name':L.get('name'),'parentId':L.get('parentId')}
    c=d.get('nextCursor')
    if not c:return o
def members(lid):
  o=set();c=None
  while True:
    p={'limit':100}
    if c:p['cursor']=c
    d=s.get(f'{b}/api/v1/lists/{lid}/bookmarks',params=p,timeout=30).json()
    for bm in d.get('bookmarks',[]):o.add(bm['id'])
    c=d.get('nextCursor')
    if not c:return o
def kidsmap(ls):
  km={}
  for lid,m in ls.items():
    pp=m.get('parentId')
    if pp:km.setdefault(pp,[]).append(lid)
  return km
def subtree(r,km):
  out=[];st=[r]
  while st:
    n=st.pop();out.append(n);st.extend(km.get(n,[]))
  return out
def depth(lid,ls):
  dd=0;cur=ls.get(lid,{}).get('parentId')
  while cur:dd+=1;cur=ls.get(cur,{}).get('parentId')
  return dd
def resolve(ls):
